```class Solution {
    public int maxTaskAssign(int[] tasks, int[] workers, int pills, int strength) {
        Arrays.sort(tasks);
        Arrays.sort(workers);
        int res = 0;
        int i = tasks.length - 1, j = workers.length - 1;
        while (i >= 0 && j >= 0) {
            if (workers[j] >= tasks[i]) {
                res++;
                i--;
                j--;
            } else if (pills > 0 && workers[j] + strength >= tasks[i]) {
                res++;
                pills--;
                i--;
                j--;
            } else {
                j--;
            }
        }
        return res;
    }
}```
